import { BarChart3 } from "lucide-react";

const Header = () => {
  return (
    <header className="p-6 bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 text-white">
      {/* Logo + Title */}
      <div className="flex items-center gap-3 mb-3">
        <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center">
          <BarChart3 size={22} className="text-white" />
        </div>
        <div>
          <h1 className="text-lg md:text-xl font-bold">StockVision</h1>
          <p className="text-blue-200 text-xs md:text-sm">JarNox Assignment</p>
        </div>
      </div>

      {/* Status Bar */}
      <div className="flex flex-wrap gap-3 text-xs md:text-sm text-blue-100">
        <span>NSE</span>
        <span>•</span>
        <span>Live Data</span>
        <span>•</span>
        <span className="flex items-center gap-1">
          <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></span>
          Active
        </span>
      </div>
    </header>
  );
};

export default Header;
